input.command:
gh api graphql -f query='
{
  repository(owner: "moltis-org", name: "moltis") {
    pullRequest(number: 529) {
      reviewThreads(first: 100) {
        nodes {
          id
          isResolved
          comments(first: 5) {
            nodes { body path line author { login } }
          }
        }
      }
    }
  }
}' 2>/dev/null | jq '.data.repository.pullRequest.reviewThreads.nodes[] | select(.isResolved == false) | {id: .id, path: .comments.nodes[0].path, line: .comments.nodes[0].line, author: .comments.nodes[0].author.login, body: (.comments.nodes[0].body | .[0:200])}'

gh api graphql -f query='
{
  repository(owner: "moltis-org", name: "moltis") {
    pullRequest(number: 529) {
      reviewThreads(first: 100) {
        nodes {
          id
          isResolved
          comments(first: 5) {
            nodes { body path line author { login } }
          }
        }
      }
    }
  }
}' 2>/dev/null | jq '[.data.repository.pullRequest.reviewThreads.nodes[] | select(.isResolved == false)]' > /tmp/greptile_threads.json && cat /tmp/greptile_threads.json | jq 'length'

